  ('generalpolice-410e2224-moex-00261', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '市政府因應嚴重天災，通知古蹟所有人辦理緊急修復。該行為之法律性質為何？', '["事實行為", "行政命令", "行政處分", "行政指導"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:39+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
