  ('generalpolice-410e2224-moex-00263', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '依行政程序法之規定與實務見解，關於行政契約之敘述，下列何者正確？', '["替代行政處分之行政契約，如與其內容相同之行政處分有得撤銷之違法原因，並為締約之一方 所明知者，為無效", "行政契約當事人一方之人民約定自願接受執行時，該約定均應經締約行政機關之上級機關之認 可，始生效力", "中央健康保險署對於與其有全民健康保險特約之醫事服務機構所為之停止特約，實務上認係契 約行為", "行政機關依法應以甄選決定行政契約當事人一方之人民時，如於決定前未給予參與甄選者表示 意見之機會，該行政契約無效"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:39+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL),
  ('generalpolice-410e2224-moex-00264', 'generalpolice-410e2224', 'generalpolice-410e2224-moex-110-3082b5f1', 'sub-generalpolice-410e2224-04', NULL, 'single_choice', '關於行政事實行為，下列敘述何者正確？', '["行政事實行為不發生法律效果，行政機關得依職權為之，不受法規規定之限制", "人民不服行政事實行為，單純拒絕即為已足，若提起行政訴訟即無權利保護必要", "行政事實行為違法侵害人民權益者，人民得向行政機關請求國家賠償", "行政事實行為僅受公法規範之拘束"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:39+00:00", "source_pdf_sha1": "4b32ba9a93cb", "answer_pdf_sha1": "a06d53ceb533", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "301", "s": "0502", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "行政管理人員"}'::jsonb, NULL)
